export const normalizeSlotMixin = extend({
  methods: {
    // Returns `true` if the either a `$scopedSlot` or `$slot` exists with the specified name
    // `name` can be a string name or an array of names
    hasNormalizedSlot(
      name = SLOT_NAME_DEFAULT,
      scopedSlots = this.$scopedSlots,
      slots = this.$slots
    ) {
      return hasNormalizedSlot(name, scopedSlots, slots)
    },
    // Returns an array of rendered VNodes if slot found, otherwise `undefined`
    // `name` can be a string name or an array of names
    normalizeSlot(
      name = SLOT_NAME_DEFAULT,
      scope = {},
      scopedSlots = this.$scopedSlots,
      slots = this.$slots
    ) {
      const vNodes = normalizeSlot(name, scope, scopedSlots, slots)
      return vNodes ? concat(vNodes) : vNodes
    }
  }
})

if (subTree) {
  if (subTree.component) {
    !suspense ? list.push(subTree.component) : list.push({ ...subTree.component, suspense })
  }
  else if (subTree.suspense) {
    const suspenseKey = !subTree.suspense.isInFallback ? 'suspense default' : 'suspense fallback'
    list.push(...this.getInternalInstanceChildren(subTree.suspense.activeBranch, { ...subTree.suspense, suspenseKey }))
  }
  else if (Array.isArray(subTree.children)) {
    subTree.children.forEach((childSubTree) => {
      if (childSubTree.component) {
        !suspense ? list.push(childSubTree.component) : list.push({ ...childSubTree.component, suspense })
      }
      else {
        list.push(...this.getInternalInstanceChildren(childSubTree, suspense))
      }
    })
  }
}

const activeRecordIndex = computed(() => {
  const route = resolvedRoute.value.route
  const { matched } = route
  const { length } = matched
  const routeMatched = matched[length - 1]
  const currentMatched = currentRoute.matched
  if (!routeMatched || !currentMatched.length) return -1
  const index = currentMatched.indexOf(routeMatched)
  if (index > -1) return index
  // possible parent record
  const parentRecord = currentMatched[currentMatched.length - 2]

  return (
    // we are dealing with nested routes
    length > 1 &&
      // if the parent and matched route have the same path, this link is
      // referring to the empty child. Or we currently are on a different
      // child of the same parent
      parentRecord && parentRecord === routeMatched.parent
  )
})

